private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    //RejOther Logic
    // --- Read values ---
if (GetCurrentColumnValue("RejOther") != null)
    rejOther = Convert.ToDecimal(GetCurrentColumnValue("RejOther"));

if (GetCurrentColumnValue("St_RejOther") != null)
    stRejOther = Convert.ToDecimal(GetCurrentColumnValue("St_RejOther"));

// --- Equation: Sum of both fields ---
rejOtherReport += rejOther ;
stRejOtherReport += stRejOther ;

//Rej Crack Logic
// --- Read values ---
if (GetCurrentColumnValue("RejCracks") != null)
    rejCracks = Convert.ToDecimal(GetCurrentColumnValue("RejCracks"));

if (GetCurrentColumnValue("St_RejCrack") != null)
    stRejCrack = Convert.ToDecimal(GetCurrentColumnValue("St_RejCrack"));

// --- Equation: Sum of both fields ---
rejCracksReport += rejCracks ;
stRejCrackReport += stRejCrack ;

//Logic for RejBroken Logic
// --- Read values ---
if (GetCurrentColumnValue("RejBroken") != null)
    rejBroken = Convert.ToDecimal(GetCurrentColumnValue("RejBroken"));

if (GetCurrentColumnValue("St_RejBroken") != null)
    stRejBroken = Convert.ToDecimal(GetCurrentColumnValue("St_RejBroken"));

rejBrokenReport += rejBroken ;
stRejBrokenReport += stRejBroken ;


//RejWhole Logic
// --- Read values ---
if (GetCurrentColumnValue("RejWhole") != null)
    rejWhole = Convert.ToDecimal(GetCurrentColumnValue("RejWhole"));

if (GetCurrentColumnValue("St_RejWhole") != null)
    stRejWhole = Convert.ToDecimal(GetCurrentColumnValue("St_RejWhole"));
rejWholeReport += rejWhole;
stRejWholeReport += stRejWhole;


}

private void xrTableCell61_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {

// --- Add to report totals (for overall sum if needed) ---
TotalRejBrokenReport = rejBrokenReport  + stRejBrokenReport ;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = TotalRejBrokenReport.ToString("N0"); // no decimals

}


