private void tdDebit_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Get the current cell ---
XRTableCell cell = sender as XRTableCell;

// --- Read value safely ---
decimal openStockReceivingHall = 0;

if (GetCurrentColumnValue("OpenStockReceivingHall") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("OpenStockReceivingHall").ToString()))
{
    openStockReceivingHall = Convert.ToDecimal(GetCurrentColumnValue("OpenStockReceivingHall"));
}
else
{
    openStockReceivingHall = 0;
}

// --- Assign the value to the cell ---
cell.Text = openStockReceivingHall.ToString("N2"); // Format with 2 decimal places

}

